const item = $input.first();
const raw = item.json.stdout.trim();
let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  throw new Error('Erro ao parsear output do frame: ' + raw);
}
return [{ json: parsed }];

const item = $input.first();

let output = '';

if (typeof item.json?.output === 'string') {
  output = item.json.output;
} else if (item.json?.message?.content) {
  output = item.json.message.content;
} else if (item.json?.choices?.[0]?.message?.content) {
  output = item.json.choices[0].message.content;
} else {
  output = JSON.stringify(item.json);
}

output = output.replace(/```json|```/g, '').trim();

const jsonMatch = output.match(/\{[\s\S]*\}/);
if (!jsonMatch) {
  throw new Error('Nenhum JSON na resposta da IA: ' + output.substring(0, 300));
}

let cropData;
try {
  cropData = JSON.parse(jsonMatch[0]);
} catch(e) {
  throw new Error('JSON inválido: ' + output.substring(0, 300));
}

const frameData = $('Processa Dados do Frame').first().json;

// ── Validação de sanidade ──────────────────────────────────────────────────
const maxW = frameData.video_width;
const maxH = frameData.video_height;

if (cropData.crop === true) {

  // 1. Se a IA retornou praticamente o frame todo (≥95% da área), ignora o crop
  const cropArea = (Number(cropData.width) || 0) * (Number(cropData.height) || 0);
  const totalArea = maxW * maxH;
  const ratio = cropArea / totalArea;

  if (ratio > 0.95) {
    return [{
      json: {
        crop: false,
        crop_x: 0,
        crop_y: 0,
        crop_width: maxW,
        crop_height: maxH,
        video_path: frameData.video_path,
        frame_path: frameData.frame_path,
        video_width: maxW,
        video_height: maxH,
        _debug: `crop ignorado — área retornada foi ${(ratio * 100).toFixed(1)}% do frame total`
      }
    }];
  }

  // 2. Clamp: garante que as coordenadas não ultrapassam os limites do frame
  const safeX = Math.max(0, Math.min(Number(cropData.x) || 0, maxW - 10));
  const safeY = Math.max(0, Math.min(Number(cropData.y) || 0, maxH - 10));
  const safeW = Math.min(Number(cropData.width) || maxW, maxW - safeX);
  const safeH = Math.min(Number(cropData.height) || maxH, maxH - safeY);

  // 3. Garante dimensões pares (exigência do libx264)
  const evenW = safeW % 2 === 0 ? safeW : safeW - 1;
  const evenH = safeH % 2 === 0 ? safeH : safeH - 1;

  // 4. Se após o clamp a área ainda for ≥95%, cancela o crop
  const clampedRatio = (evenW * evenH) / totalArea;
  if (clampedRatio > 0.95) {
    return [{
      json: {
        crop: false,
        crop_x: 0,
        crop_y: 0,
        crop_width: maxW,
        crop_height: maxH,
        video_path: frameData.video_path,
        frame_path: frameData.frame_path,
        video_width: maxW,
        video_height: maxH,
        _debug: `crop cancelado após clamp — área ainda era ${(clampedRatio * 100).toFixed(1)}%`
      }
    }];
  }

  return [{
    json: {
      crop: true,
      crop_x: safeX,
      crop_y: safeY,
      crop_width: evenW,
      crop_height: evenH,
      video_path: frameData.video_path,
      frame_path: frameData.frame_path,
      video_width: maxW,
      video_height: maxH,
      _debug: `crop aplicado — x:${safeX} y:${safeY} w:${evenW} h:${evenH} (${(clampedRatio * 100).toFixed(1)}% do frame)`
    }
  }];
}

// ── Sem crop ───────────────────────────────────────────────────────────────
return [{
  json: {
    crop: false,
    crop_x: 0,
    crop_y: 0,
    crop_width: maxW,
    crop_height: maxH,
    video_path: frameData.video_path,
    frame_path: frameData.frame_path,
    video_width: maxW,
    video_height: maxH,
    _debug: 'IA indicou que não há crop necessário'
  }
}];

const item = $input.first();

// O nó retorna array ou objeto — normaliza para objeto
const json = Array.isArray(item.json) ? item.json[0] : item.json;

// Pega o texto direto de content[0].text
const rawText = json?.content?.[0]?.text ?? '';

if (!rawText) {
  throw new Error('Texto não encontrado. JSON: ' + JSON.stringify(json).substring(0, 300));
}

// Parseia o JSON do crop
let cropData;
try {
  cropData = JSON.parse(rawText.replace(/```json|```/g, '').trim());
} catch(e) {
  throw new Error('JSON inválido: ' + rawText);
}

if (typeof cropData.crop === 'undefined') {
  throw new Error('Campo crop ausente: ' + rawText);
}

// ── FRAME DATA ────────────────────────────────────────────────────────────
let frameData = null;
for (const fonte of ['Salva URL do Frame', 'Processa Dados do Frame']) {
  try {
    const d = $(fonte).first().json;
    if (d?.video_width && d?.video_height && d?.video_path) { frameData = d; break; }
  } catch(e) {}
}
if (!frameData) throw new Error('frameData não encontrado');

const maxW = Number(frameData.video_width);
const maxH = Number(frameData.video_height);
const totalArea = maxW * maxH;

// ── LÓGICA DE CROP ────────────────────────────────────────────────────────
if (cropData.crop === true) {
  const rawX = Number(cropData.x) || 0;
  const rawY = Number(cropData.y) || 0;
  const rawW = Number(cropData.width) || maxW;
  const rawH = Number(cropData.height) || maxH;

  const rawRatio = (rawW * rawH) / totalArea;
  if (rawRatio > 0.95) {
    return [{ json: { crop: false, crop_x: 0, crop_y: 0, crop_width: maxW, crop_height: maxH, video_path: frameData.video_path, frame_path: frameData.frame_path, video_width: maxW, video_height: maxH, _debug: `crop ignorado — ${(rawRatio*100).toFixed(1)}% do frame` } }];
  }

  const safeX = Math.max(0, Math.min(rawX, maxW - 10));
  const safeY = Math.max(0, Math.min(rawY, maxH - 10));
  const evenW = Math.min(rawW, maxW - safeX);
  const evenH = Math.min(rawH, maxH - safeY);
  const fW = evenW % 2 === 0 ? evenW : evenW - 1;
  const fH = evenH % 2 === 0 ? evenH : evenH - 1;

  const clampedRatio = (fW * fH) / totalArea;
  if (clampedRatio > 0.95) {
    return [{ json: { crop: false, crop_x: 0, crop_y: 0, crop_width: maxW, crop_height: maxH, video_path: frameData.video_path, frame_path: frameData.frame_path, video_width: maxW, video_height: maxH, _debug: `crop cancelado pós-clamp — ${(clampedRatio*100).toFixed(1)}%` } }];
  }

  return [{ json: { crop: true, crop_x: safeX, crop_y: safeY, crop_width: fW, crop_height: fH, video_path: frameData.video_path, frame_path: frameData.frame_path, video_width: maxW, video_height: maxH, _debug: `crop aplicado — x:${safeX} y:${safeY} w:${fW} h:${fH} | ${(clampedRatio*100).toFixed(1)}%` } }];
}

return [{ json: { crop: false, crop_x: 0, crop_y: 0, crop_width: maxW, crop_height: maxH, video_path: frameData.video_path, frame_path: frameData.frame_path, video_width: maxW, video_height: maxH, _debug: 'IA indicou sem crop' } }];
